<template><view class="page"><xy-header title="会员动态码"/><view class="card"><text class="label">到店向工作人员出示</text><text class="code">{{code||'--------'}}</text><text class="expire">{{remaining>0?`${remaining} 秒后失效`:'动态码已失效'}}</text><button @click="refresh">刷新动态码</button></view></view></template>
<script>import{appRequest,ensureMemberSession,showRequestError}from'../../utils/api';export default{data(){return{code:'',remaining:0,timer:null}},onLoad(){this.refresh()},onUnload(){clearInterval(this.timer)},methods:{async refresh(){try{await ensureMemberSession();const data=await appRequest({url:'/app/membership-code'});this.code=data.code;this.remaining=data.expiresIn;clearInterval(this.timer);this.timer=setInterval(()=>{if(this.remaining>0)this.remaining--;else clearInterval(this.timer)},1000)}catch(e){showRequestError(e)}}}}</script>
<style scoped>.page{min-height:100vh;padding:80rpx 36rpx;background:var(--xy-bg)}.card{display:flex;flex-direction:column;align-items:center;gap:28rpx;padding:60rpx 30rpx;border-radius:30rpx;background:#fff}.label,.expire{color:var(--xy-muted)}.code{font-size:64rpx;font-weight:800;letter-spacing:10rpx;color:var(--xy-primary)}button{background:var(--xy-primary);color:#fff}</style>
